        let conv = fs::read_to_string(&conv_path).unwrap();
        let state: ConvergenceState = serde_json::from_str(&conv).unwrap();
        assert_eq!(state.observations.len(), 2);
        assert_eq!(state.observations[0].signal, "first_signal");
